// Story 1-6: TEA Risk-Based Tests -- Seed Data & Org Templates
// Generated by TEA (Test Architect) automate workflow
import { describe, test, expect } from 'bun:test'
import {
  CHIEF_OF_STAFF_SOUL,
  BUILTIN_TEMPLATES,
  INVESTMENT_TEMPLATE,
  MARKETING_TEMPLATE,
  ALL_IN_ONE_TEMPLATE,
  type TemplateData,
  type TemplateAgent,
  type TemplateDepartment,
} from '../../services/seed.service'

// =============================================
// P0: templateData 스키마 호환성 (DB jsonb 저장 검증)
// =============================================
describe('TEA P0: templateData Schema Compliance', () => {
  const allTemplates = [
    { name: '투자분석', data: INVESTMENT_TEMPLATE },
    { name: '마케팅', data: MARKETING_TEMPLATE },
    { name: '올인원', data: ALL_IN_ONE_TEMPLATE },
  ]

  for (const { name, data } of allTemplates) {
    test(`${name} -- departments는 비어있지 않은 배열이어야 함`, () => {
      expect(Array.isArray(data.departments)).toBe(true)
      expect(data.departments.length).toBeGreaterThan(0)
    })

    test(`${name} -- 모든 부서에 name(string)이 있어야 함`, () => {
      for (const dept of data.departments) {
        expect(typeof dept.name).toBe('string')
        expect(dept.name.length).toBeGreaterThan(0)
      }
    })

    test(`${name} -- 모든 에이전트에 필수 6개 필드가 있어야 함`, () => {
      const requiredFields: (keyof TemplateAgent)[] = ['name', 'role', 'tier', 'modelName', 'soul', 'allowedTools']
      for (const dept of data.departments) {
        for (const agent of dept.agents) {
          for (const field of requiredFields) {
            expect(agent[field]).toBeDefined()
            expect(agent[field]).not.toBeNull()
          }
        }
      }
    })

    test(`${name} -- tier는 정확히 3가지 값 중 하나여야 함`, () => {
      const validTiers = new Set(['manager', 'specialist', 'worker'])
      for (const dept of data.departments) {
        for (const agent of dept.agents) {
          expect(validTiers.has(agent.tier)).toBe(true)
        }
      }
    })

    test(`${name} -- modelName은 claude- 접두사로 시작해야 함`, () => {
      for (const dept of data.departments) {
        for (const agent of dept.agents) {
          expect(agent.modelName).toMatch(/^claude-/)
        }
      }
    })

    test(`${name} -- allowedTools의 모든 항목은 비어있지 않은 string이어야 함`, () => {
      for (const dept of data.departments) {
        for (const agent of dept.agents) {
          for (const tool of agent.allowedTools) {
            expect(typeof tool).toBe('string')
            expect(tool.length).toBeGreaterThan(0)
            expect(tool).not.toContain(' ') // 도구 이름에 공백 없음
          }
        }
      }
    })
  }
})

