// =============================================
// P0: 3계급 모델 배정 정합성
// =============================================
describe('TEA P0: Three-Tier Model Assignment', () => {
  const MANAGER_MODEL = 'claude-sonnet-4-6'
  const NON_MANAGER_MODEL = 'claude-haiku-4-5'

  const allAgents: Array<{ template: string; dept: string; agent: TemplateAgent }> = []
  for (const tmpl of BUILTIN_TEMPLATES) {
    for (const dept of tmpl.templateData.departments) {
      for (const agent of dept.agents) {
        allAgents.push({ template: tmpl.name, dept: dept.name, agent })
      }
    }
  }

  test('Manager 에이전트는 항상 Sonnet 모델이어야 함', () => {
    const managers = allAgents.filter(a => a.agent.tier === 'manager')
    expect(managers.length).toBeGreaterThan(0)
    for (const m of managers) {
      expect(m.agent.modelName).toBe(MANAGER_MODEL)
    }
  })

  test('Specialist 에이전트는 항상 Haiku 모델이어야 함', () => {
    const specialists = allAgents.filter(a => a.agent.tier === 'specialist')
    expect(specialists.length).toBeGreaterThan(0)
    for (const s of specialists) {
      expect(s.agent.modelName).toBe(NON_MANAGER_MODEL)
    }
  })

  test('Worker 에이전트는 항상 Haiku 모델이어야 함', () => {
    const workers = allAgents.filter(a => a.agent.tier === 'worker')
    expect(workers.length).toBeGreaterThan(0)
    for (const w of workers) {
      expect(w.agent.modelName).toBe(NON_MANAGER_MODEL)
    }
  })
})

