// P1: allowedTools 유효성 (실제 도구 이름 매칭)
// =============================================
describe('TEA P1: allowedTools Validity', () => {
  // 시드에서 정의된 실제 도구 이름들
  const KNOWN_TOOLS = new Set([
    'get_current_time', 'calculate', 'search_department_knowledge',
    'get_company_info', 'search_web', 'search_news', 'search_images',
    'search_youtube', 'search_places', 'create_report',
    'send_email', 'list_calendar_events', 'create_calendar_event',
    'read_notion_page', 'create_notion_page', 'generate_text_file',
    'get_stock_price', 'get_account_balance', 'place_stock_order',
    'text_to_speech', 'generate_image', 'translate_text',
    'publish_instagram', 'get_instagram_insights',
  ])

  for (const tmpl of BUILTIN_TEMPLATES) {
    for (const dept of tmpl.templateData.departments) {
      for (const agent of dept.agents) {
        test(`${tmpl.name}/${dept.name}/${agent.name} -- 모든 도구가 알려진 도구 목록에 있어야 함`, () => {
          for (const tool of agent.allowedTools) {
            expect(KNOWN_TOOLS.has(tool)).toBe(true)
          }
        })
      }
    }
  }
})

