// =============================================
// P1: Soul 마크다운에 SQL/코드 인젝션 위험 없음
// =============================================
describe('TEA P1: Soul Content Safety', () => {
  const allSouls: string[] = [CHIEF_OF_STAFF_SOUL]
  for (const tmpl of BUILTIN_TEMPLATES) {
    for (const dept of tmpl.templateData.departments) {
      for (const agent of dept.agents) {
        allSouls.push(agent.soul)
      }
    }
  }

  test('어떤 Soul에도 SQL 키워드가 없어야 함', () => {
    const sqlPatterns = /\b(DROP TABLE|DELETE FROM|INSERT INTO|UPDATE .+ SET|ALTER TABLE)\b/i
    for (const soul of allSouls) {
      expect(sqlPatterns.test(soul)).toBe(false)
    }
  })

  test('어떤 Soul에도 script 태그가 없어야 함', () => {
    for (const soul of allSouls) {
      expect(soul.toLowerCase()).not.toContain('<script')
    }
  })
})

// =============================================
// P2: BUILTIN_TEMPLATES readonly 계약
// =============================================
describe('TEA P2: Template Immutability Contract', () => {
  test('BUILTIN_TEMPLATES 배열 길이가 정확히 3이어야 함', () => {
    expect(BUILTIN_TEMPLATES).toHaveLength(3)
  })

  test('각 템플릿 name이 정확한 한국어여야 함', () => {
    expect(BUILTIN_TEMPLATES[0].name).toBe('투자분석')
    expect(BUILTIN_TEMPLATES[1].name).toBe('마케팅')
    expect(BUILTIN_TEMPLATES[2].name).toBe('올인원')
  })

  test('투자분석 에이전트 수가 정확히 5명이어야 함', () => {
    const count = INVESTMENT_TEMPLATE.departments.reduce((s, d) => s + d.agents.length, 0)
    expect(count).toBe(5)
  })

  test('마케팅 에이전트 수가 정확히 4명이어야 함', () => {
    const count = MARKETING_TEMPLATE.departments.reduce((s, d) => s + d.agents.length, 0)
    expect(count).toBe(4)
  })

  test('올인원 에이전트 수가 정확히 12명이어야 함', () => {
    const count = ALL_IN_ONE_TEMPLATE.departments.reduce((s, d) => s + d.agents.length, 0)
    expect(count).toBe(12)
  })
})

